local color = 'White' local r = 1 local g = 1 local b = 1
function onValueChanged(eventType) if eventType == 'x' and self.values.x == 1 then if self.values.x == 1 then local redFader = root:findByName('Color Picker Red Fader',true) local greenFader = root:findByName('Color Picker Green Fader',true) local blueFader = root:findByName('Color Picker Blue Fader',true)
redFader.values.x = r; greenFader.values.x = g; blueFader.values.x = b;
redFader:notify('Send Update',nil) greenFader:notify('Send Update',nil) blueFader:notify('Send Update',nil)
local allQLCButtons = root:findAllByProperty('tag','QLCBUTTON',true); for i = 1,#allQLCButtons do local currentButton = allQLCButtons[i] if currentButton.values.x == 1 then currentButton:notify('Color Change Button',color) end end end end end

