local myMacros = {
  {name = 'Off'},
}

function onValueChanged(eventType)
  if eventType == 'x' and self.values.x == 1 then
    local macroPicker = root:findByProperty('tag','Macro Picker',true)
    macroPicker:notify('setMacro',{lightName = self.parent.tag , macros = myMacros})
  end
end

